const payload = $json.body && typeof $json.body === 'object' ? $json.body : $json;
const from = (payload.from ?? payload.from_email ?? '').toString().trim();
const subjectRaw = (payload.subject ?? '').toString().trim();
const bodyRaw = (payload.body ?? '').toString().trim();
const subject = subjectRaw.replace(/^(re:|fwd:|fw:)\s*/i, '').replace(/\s+/g, ' ').trim();
const body = bodyRaw.replace(/\r\n/g, '\n').replace(/\r/g, '\n').replace(/\n{3,}/g, '\n\n').replace(/\s+/g, ' ').trim().slice(0, 4000);
const combined = `${subject}\n${body}`.toLowerCase();
const highRiskKeywords = ['soc 2', 'hipaa', 'baa', 'gdpr', 'dpa', 'contract', 'legal', 'security', 'encryption', 'breach', 'vulnerability', 'pentest', 'penetration test', 'invoice dispute', 'refund', 'discount', 'enterprise plan', 'custom quote'];
const isHighRisk = highRiskKeywords.some((keyword) => combined.includes(keyword));
const lexicalMultiIntent = /(also|another question|one more thing|as well as|and separately)\b/i.test(`${subject}\n${body}`);
return [{
  from,
  subject,
  body,
  query_text: `Subject: ${subject}\nBody: ${body}`,
  is_high_risk: isHighRisk,
  lexical_multi_intent: lexicalMultiIntent,
  received_at: new Date().toISOString()
}];

const text = `${$json.subject}\n${$json.body}`.toLowerCase();
let fastPath = false;
let category = '';
let routeTeam = 'support';
let needsEscalation = false;
let draftReply = '';

if (/\b(statement|checking account|bank account|monthly checking)\b/.test(text)) {
  fastPath = true;
  category = 'Misdirected / Wrong Recipient';
  routeTeam = 'none';
  needsEscalation = false;
  draftReply = 'Thanks for your message. This inbox belongs to Nexus Integrations support and appears to be the wrong recipient.';
} else if (/\b(recruiter|candidates available|schedule a call)\b/.test(text)) {
  fastPath = true;
  category = 'Spam / Vendor Solicitation';
  routeTeam = 'none';
  needsEscalation = false;
  draftReply = 'Thank you for reaching out. We are not exploring recruiter/vendor solicitations through this support channel at the moment.';
}

return [{ ...$json, fast_path: fastPath, fast_path_output: {
  category,
  draft_reply: draftReply,
  confidence: fastPath ? 0.98 : 0,
  needs_escalation: needsEscalation,
  route_team: routeTeam,
  evidence_refs: ['regex_fast_path']
}}];

const vector = $json.data?.[0]?.embedding ?? [];
const prior = { ...$json };
delete prior.data;
return [{ ...prior, embedding_vector: vector }];

const matches = Array.isArray($json.matches ?? $json.data) ? ($json.matches ?? $json.data) : [];
const toNumber = (value, fallback = 0) => {
  const parsed = Number(value);
  return Number.isFinite(parsed) ? parsed : fallback;
};
const clamp = (value) => {
  const numeric = toNumber(value);
  return Math.max(0, Math.min(1, Number(numeric.toFixed(4))));
};
const pickCategory = (match) => (match?.metadata?.normalized_category ?? match?.metadata?.category ?? match?.metadata?.label ?? match?.category ?? '').toString().trim();
const top1 = toNumber(matches?.[0]?.score);
const top2 = toNumber(matches?.[1]?.score);
const rerank = toNumber(matches?.[0]?.rerank_score, top1);
const margin = Math.max(0, top1 - top2);
const score = clamp((0.5 * top1) + (0.3 * margin) + (0.2 * rerank));
const topCategories = matches.slice(0, 3).map(pickCategory).filter(Boolean);
const uniqueTopCategories = [...new Set(topCategories)];
const noveltySignals = [];
if (top1 < 0.72) noveltySignals.push('low_sim_top1');
if (margin < 0.05) noveltySignals.push('small_margin');
if (rerank < 0.68) noveltySignals.push('low_rerank');
if (uniqueTopCategories.length > 1) noveltySignals.push('mixed_top_categories');
const noveltyDetected = noveltySignals.length >= 2;
const ambiguousRetrieval = margin < 0.08 || uniqueTopCategories.length > 1;
return [{
  ...$json,
  retrieved_examples: matches.slice(0, 3),
  retrieval_primary_category: topCategories[0] ?? '',
  retrieval_top_categories: uniqueTopCategories,
  sim_top1: top1,
  sim_top2: top2,
  rerank_score: rerank,
  retrieval_margin: clamp(margin),
  confidence_score: score,
  retrieval_novelty_signals: noveltySignals,
  novelty_detected: noveltyDetected,
  ambiguous_retrieval: ambiguousRetrieval,
  should_use_tier2: Boolean($json.is_high_risk) || Boolean($json.lexical_multi_intent) || noveltyDetected || score < 0.82
}];

const raw = $json.output ?? $json.response ?? $json;
let parsed = raw;
if (typeof raw === 'string') {
  try {
    parsed = JSON.parse(raw);
  } catch {
    parsed = {};
  }
}
const toNumber = (value, fallback = 0) => {
  const numeric = Number(value);
  return Number.isFinite(numeric) ? numeric : fallback;
};
const clamp = (value) => Math.max(0, Math.min(1, Number(toNumber(value).toFixed(4))));
const asStringArray = (value) => Array.isArray(value) ? value.map((item) => item.toString().trim()).filter(Boolean) : [];
const asCandidateArray = (value) => Array.isArray(value)
  ? value
      .map((candidate) => ({
        label: (candidate?.label ?? candidate?.category ?? '').toString().trim(),
        score: clamp(candidate?.score ?? candidate?.confidence ?? 0)
      }))
      .filter((candidate) => candidate.label)
  : [];
const defaultRouteByCategory = {
  'Setup Question': 'support',
  'Security Question': 'security',
  'Pricing Question': 'sales',
  'Job Application / HR': 'people',
  'Partnership / Business Development': 'sales',
  'Spam / Vendor Solicitation': 'none',
  'Billing / Finance': 'finance',
  'Contract / Legal': 'legal',
  'Misdirected / Wrong Recipient': 'none',
  'Legal / Compliance': 'legal'
};
const thresholds = {
  __default: { autoReply: 0.82, humanReview: 0.68, minEvidenceItems: 2, minTopEvidenceScore: 0.74 },
  'Setup Question': { autoReply: 0.82, humanReview: 0.68, minEvidenceItems: 2, minTopEvidenceScore: 0.74 },
  'Security Question': { autoReply: 0.88, humanReview: 0.76, minEvidenceItems: 2, minTopEvidenceScore: 0.8 },
  'Pricing Question': { autoReply: 0.86, humanReview: 0.72, minEvidenceItems: 1, minTopEvidenceScore: 0.76 },
  'Spam / Vendor Solicitation': { autoReply: 0.9, humanReview: 0.7, minEvidenceItems: 0, minTopEvidenceScore: 0 },
  'Misdirected / Wrong Recipient': { autoReply: 0.9, humanReview: 0.7, minEvidenceItems: 0, minTopEvidenceScore: 0 }
};
/* SYNC: knowledgePolicies must stay in sync with src/config/structured_knowledge.json category_policies */
const knowledgePolicies = {
  __default: { sourceMode: 'hybrid', requiresStructuredFacts: false, requiresKbLookup: true, requiredFactSets: [] },
  'Setup Question': { sourceMode: 'hybrid', requiresStructuredFacts: false, requiresKbLookup: true, requiredFactSets: ['integration_catalog', 'setup_prerequisites'] },
  'Security Question': { sourceMode: 'structured_first', requiresStructuredFacts: true, requiresKbLookup: true, requiredFactSets: ['security_capability_matrix', 'trust_policy_register', 'security_contact_policy'] },
  'Pricing Question': { sourceMode: 'structured_first', requiresStructuredFacts: true, requiresKbLookup: false, requiredFactSets: ['plan_catalog', 'pricing_policy', 'sales_handoff_policy'] },
  'Job Application / HR': { sourceMode: 'review_only', requiresStructuredFacts: false, requiresKbLookup: false, requiredFactSets: [] },
  'Partnership / Business Development': { sourceMode: 'review_only', requiresStructuredFacts: false, requiresKbLookup: false, requiredFactSets: [] },
  'Spam / Vendor Solicitation': { sourceMode: 'no_lookup', requiresStructuredFacts: false, requiresKbLookup: false, requiredFactSets: [] },
  'Billing / Finance': { sourceMode: 'review_only', requiresStructuredFacts: false, requiresKbLookup: false, requiredFactSets: [] },
  'Contract / Legal': { sourceMode: 'review_only', requiresStructuredFacts: false, requiresKbLookup: false, requiredFactSets: [] },
  'Misdirected / Wrong Recipient': { sourceMode: 'no_lookup', requiresStructuredFacts: false, requiresKbLookup: false, requiredFactSets: [] },
  'Legal / Compliance': { sourceMode: 'review_only', requiresStructuredFacts: false, requiresKbLookup: false, requiredFactSets: [] }
};
const blockedAutoReplyCategories = new Set(['Job Application / HR', 'Partnership / Business Development', 'Billing / Finance', 'Contract / Legal', 'Legal / Compliance']);
const reviewRiskTags = new Set(['legal', 'security', 'compliance', 'pricing_negotiation', 'billing_dispute', 'unknown_policy_gap', 'contract_request', 'incident_report']);
const category = (parsed.category ?? $json.retrieval_primary_category ?? 'Setup Question').toString().trim() || 'Setup Question';
const categoryCandidates = asCandidateArray(parsed.category_candidates).sort((left, right) => right.score - left.score).slice(0, 3);
if (!categoryCandidates.some((candidate) => candidate.label === category)) {
  categoryCandidates.unshift({ label: category, score: clamp(parsed.confidence ?? $json.confidence_score ?? 0.5) });
}
const trimmedCandidates = categoryCandidates.slice(0, 3);
let secondaryCategories = asStringArray(parsed.secondary_categories).filter((item) => item !== category).slice(0, 2);
if (!secondaryCategories.length && trimmedCandidates.length > 1 && trimmedCandidates[1].score >= 0.45) {
  secondaryCategories = [trimmedCandidates[1].label];
}
const riskTags = [...new Set(asStringArray(parsed.risk_tags).concat($json.lexical_multi_intent ? ['multi_intent'] : []))];
const routeTeam = (parsed.route_team ?? defaultRouteByCategory[category] ?? 'support').toString();
const selectedThresholds = thresholds[category] ?? thresholds.__default;
const selectedKnowledgePolicy = knowledgePolicies[category] ?? knowledgePolicies.__default;
const retrievalPrimaryCategory = ($json.retrieval_primary_category ?? '').toString().trim();
const retrievalAgreement = !retrievalPrimaryCategory || retrievalPrimaryCategory === category || secondaryCategories.includes(retrievalPrimaryCategory) || trimmedCandidates.some((candidate) => candidate.label === retrievalPrimaryCategory && candidate.score >= 0.45);
const candidateMargin = trimmedCandidates.length > 1 ? Math.max(0, trimmedCandidates[0].score - trimmedCandidates[1].score) : trimmedCandidates[0]?.score ?? 0;
const multiIntent = Boolean($json.lexical_multi_intent) || secondaryCategories.length > 0 || (trimmedCandidates.length > 1 && candidateMargin < 0.12) || riskTags.includes('multi_intent');
let categoryConfidence = Math.max(clamp(parsed.confidence ?? 0), clamp($json.confidence_score ?? 0));
categoryConfidence += Math.min(0.08, candidateMargin * 0.4);
if (!retrievalAgreement) categoryConfidence -= 0.12;
if (Boolean($json.novelty_detected)) categoryConfidence -= 0.1;
if (Boolean($json.ambiguous_retrieval)) categoryConfidence -= 0.08;
if (multiIntent) categoryConfidence -= 0.08;
categoryConfidence = clamp(categoryConfidence);
const escalationReasons = [];
if (Boolean(parsed.needs_escalation)) escalationReasons.push('classifier_requested_escalation');
if (blockedAutoReplyCategories.has(category)) escalationReasons.push('category_blocked_for_auto_reply');
if (Boolean($json.is_high_risk)) escalationReasons.push('keyword_high_risk');
if (riskTags.some((tag) => reviewRiskTags.has(tag))) escalationReasons.push('risk_tag_requires_review');
if (!retrievalAgreement) escalationReasons.push('retrieval_classifier_disagreement');
if (Boolean($json.novelty_detected)) escalationReasons.push('novel_case');
if (Boolean($json.ambiguous_retrieval)) escalationReasons.push('ambiguous_retrieval');
if (multiIntent) escalationReasons.push('multi_intent');
if (categoryConfidence < selectedThresholds.autoReply) escalationReasons.push('below_auto_reply_threshold');
if (categoryConfidence < selectedThresholds.humanReview) escalationReasons.push('low_category_confidence');
const replyQueryText = `${$json.query_text}\nPredicted category: ${category}` + (secondaryCategories.length ? `\nSecondary intents: ${secondaryCategories.join(', ')}` : '');
return [{
  ...$json,
  category,
  category_candidates: trimmedCandidates,
  secondary_categories: secondaryCategories,
  risk_tags: riskTags,
  route_team: routeTeam,
  needs_escalation: escalationReasons.length > 0,
  confidence: categoryConfidence,
  category_confidence: categoryConfidence,
  auto_reply_threshold: selectedThresholds.autoReply,
  human_review_threshold: selectedThresholds.humanReview,
  min_kb_evidence_items: selectedThresholds.minEvidenceItems,
  min_kb_top_score: selectedThresholds.minTopEvidenceScore,
  retrieval_agreement: retrievalAgreement,
  knowledge_source_preference: selectedKnowledgePolicy.sourceMode,
  requires_structured_facts: selectedKnowledgePolicy.requiresStructuredFacts,
  requires_kb_lookup: selectedKnowledgePolicy.requiresKbLookup,
  required_fact_sets: selectedKnowledgePolicy.requiredFactSets,
  grounding_evidence: [],
  escalation_reasons: [...new Set(escalationReasons)],
  reply_query_text: replyQueryText
}];

/* Upstream: Parse Classifier - do not depend on API response echo */
const base = $('Parse Classifier').item.json;
const isError = Boolean($json.error);
const response = isError ? {} : $json;
const rawFacts = isError ? [] : (Array.isArray(response.facts) ? response.facts : Array.isArray(response.data?.facts) ? response.data.facts : []);
const toNumber = (value, fallback = 0) => {
  const numeric = Number(value);
  return Number.isFinite(numeric) ? numeric : fallback;
};
const clamp = (value) => Math.max(0, Math.min(1, Number(toNumber(value).toFixed(4))));
const requiredFactSets = Array.isArray(base.required_fact_sets) ? base.required_fact_sets : [];
const sourceMode = (base.knowledge_source_preference ?? 'hybrid').toString();
const coverage = clamp(response.coverage ?? response.data?.coverage ?? (rawFacts.length ? Math.min(1, rawFacts.length / Math.max(1, requiredFactSets.length || rawFacts.length)) : 0));
const answerable = Boolean(response.answerable ?? response.data?.answerable ?? rawFacts.length > 0);
const requiresDocumentRetrieval = Boolean(response.requires_document_retrieval ?? response.data?.requires_document_retrieval ?? base.requires_kb_lookup ?? false);
const structuredEvidence = rawFacts.slice(0, 5).map((fact, index) => ({
  id: (fact?.id ?? `structured_${index + 1}`).toString(),
  type: 'structured_fact',
  title: (fact?.title ?? fact?.name ?? `Structured fact ${index + 1}`).toString(),
  content: (fact?.value ?? fact?.content ?? JSON.stringify(fact)).toString(),
  source_ref: (fact?.source_ref ?? fact?.source ?? 'structured_lookup').toString(),
  score: clamp(fact?.confidence ?? coverage || 0.85)
}));
const needsKbLookup = isError || (sourceMode !== 'no_lookup' && (requiresDocumentRetrieval || !answerable || (Boolean(base.requires_structured_facts) && structuredEvidence.length === 0)));
const escalationReasons = Array.isArray(base.escalation_reasons) ? [...base.escalation_reasons] : [];
if (isError) escalationReasons.push('structured_lookup_failed');
if (Boolean(base.requires_structured_facts) && structuredEvidence.length === 0) escalationReasons.push('missing_structured_facts');
if (!answerable && sourceMode !== 'no_lookup') escalationReasons.push('structured_lookup_inconclusive');
return [{
  ...base,
  structured_facts: structuredEvidence,
  structured_fact_ids: structuredEvidence.map((fact) => fact.id),
  structured_fact_coverage: coverage,
  structured_answerable: answerable,
  requires_kb_lookup: needsKbLookup,
  evidence_confidence: structuredEvidence.length ? coverage : 0,
  reply_strategy: !needsKbLookup && structuredEvidence.length ? 'structured_grounded_reply' : (base.reply_strategy ?? 'grounded_reply'),
  grounding_evidence: structuredEvidence,
  needs_escalation: escalationReasons.length > 0 || Boolean(base.needs_escalation),
  escalation_reasons: [...new Set(escalationReasons)]
}];

/* Upstream: Assess Structured Facts - do not depend on API response echo */
const upstream = $('Assess Structured Facts').item.json;
const documentMatches = Array.isArray($json.matches ?? $json.data) ? ($json.matches ?? $json.data) : [];
const structuredEvidence = Array.isArray(upstream.grounding_evidence) ? upstream.grounding_evidence : [];
const toNumber = (value, fallback = 0) => {
  const numeric = Number(value);
  return Number.isFinite(numeric) ? numeric : fallback;
};
const clamp = (value) => Math.max(0, Math.min(1, Number(toNumber(value).toFixed(4))));
const normalizedDocumentEvidence = documentMatches.slice(0, 4).map((match, index) => ({
  id: (match?.id ?? match?.metadata?.id ?? `kb_${index + 1}`).toString(),
  type: 'document_chunk',
  title: (match?.metadata?.title ?? match?.metadata?.section ?? `KB evidence ${index + 1}`).toString(),
  content: (match?.text ?? match?.metadata?.text ?? match?.metadata?.excerpt ?? '').toString(),
  source_ref: (match?.metadata?.source_url ?? match?.metadata?.source_ref ?? 'kb_policy').toString(),
  score: clamp(match?.score ?? match?.similarity ?? match?.rerank_score)
}));
const topDocScore = toNumber(documentMatches?.[0]?.score ?? documentMatches?.[0]?.similarity ?? documentMatches?.[0]?.rerank_score);
const topEvidenceScore = Math.max(clamp(upstream.structured_fact_coverage ?? 0), clamp(topDocScore));
const combinedEvidence = structuredEvidence.concat(normalizedDocumentEvidence);
const evidenceCount = combinedEvidence.length;
const minEvidenceItems = Math.max(0, Math.trunc(toNumber(upstream.min_kb_evidence_items, 2)));
const minTopEvidenceScore = clamp(upstream.min_kb_top_score ?? 0.72);
const evidenceConfidence = evidenceCount === 0 ? 0 : clamp((0.75 * topEvidenceScore) + (0.25 * (Math.min(evidenceCount, 3) / 3)));
const escalationReasons = Array.isArray(upstream.escalation_reasons) ? [...upstream.escalation_reasons] : [];
const evidenceInsufficient = evidenceCount < minEvidenceItems || topEvidenceScore < minTopEvidenceScore;
if (evidenceInsufficient) escalationReasons.push('insufficient_grounding_evidence');
return [{
  ...upstream,
  kb_matches: normalizedDocumentEvidence,
  kb_evidence_count: normalizedDocumentEvidence.length,
  kb_top_score: clamp(topDocScore),
  evidence_confidence: evidenceConfidence,
  grounding_evidence: combinedEvidence.slice(0, 6),
  needs_escalation: Boolean(upstream.needs_escalation) || evidenceInsufficient,
  escalation_reasons: [...new Set(escalationReasons)],
  reply_strategy: evidenceInsufficient ? 'acknowledge_and_escalate' : (structuredEvidence.length ? 'hybrid_grounded_reply' : 'document_grounded_reply')
}];

const raw = $json.output ?? $json.response ?? $json;
let parsed = raw;
if (typeof raw === 'string') {
  try { parsed = JSON.parse(raw); } catch { parsed = {}; }
}
const asStringArray = (value) => Array.isArray(value) ? value.map((item) => item.toString()) : [];
const evidenceIds = asStringArray(parsed.used_evidence_ids);
const fallbackEvidenceIds = Array.isArray($json.grounding_evidence)
  ? $json.grounding_evidence.slice(0, 3).map((evidence, index) => (evidence?.id ?? `evidence_${index + 1}`).toString())
  : [];
const escalationReasons = Array.isArray($json.escalation_reasons) ? [...$json.escalation_reasons] : [];
const groundingOk = parsed.grounding_ok !== false;
if (!groundingOk) escalationReasons.push('reply_grounding_not_confirmed');
const needsEscalation = Boolean($json.needs_escalation) || !groundingOk;
return [{
  category: $json.category,
  draft_reply: parsed.draft_reply ?? (needsEscalation ? 'Thanks for your message. We are routing your request to the right team for confirmation.' : 'Thanks for your email. Here is the guidance we can provide based on our verified sources.'),
  confidence: $json.confidence ?? $json.category_confidence ?? $json.confidence_score ?? 0.5,
  category_confidence: $json.category_confidence ?? $json.confidence ?? 0.5,
  evidence_confidence: $json.evidence_confidence ?? 0,
  needs_escalation: needsEscalation,
  route_team: $json.route_team ?? 'support',
  evidence_refs: evidenceIds.length ? evidenceIds : fallbackEvidenceIds,
  secondary_categories: $json.secondary_categories ?? [],
  risk_tags: $json.risk_tags ?? [],
  escalation_reasons: [...new Set(escalationReasons)]
}];
